func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Initialize the Lua VM with restricted options to enhance security.
	// SkipOpenLibs prevents the automatic loading of standard libraries like 'os', 'io', and 'debug',
	// which could otherwise be used to execute arbitrary system commands or access the file system.
	L := lua.NewState(lua.Options{
